"use strict";(()=>{(function(){document.querySelectorAll(".codeblock__copy").forEach(function(e){e.addEventListener("click",function(){var t=e.closest(".codeblock"),n=t?t.querySelector("code"):null;if(!n)return;navigator.clipboard.writeText(n.innerText).then(function(){e.classList.add("codeblock__copy--done"),setTimeout(function(){e.classList.remove("codeblock__copy--done")},2e3)})})})})()})()